%[text] # 6주차 동영상
%[text] ## Polar / Plot / Patch
%[text] 
%Polar, Plot, and Patch Demo

%a wing
t1 = 0:0.01:pi/3; %counter clock wise 60도
tr = t1(end:-1:1); %clockwise wing의 짧은 부분
nt = length(t1);
th = [t1 tr 0]; %theta 값
r1 = [ones(1, nt) 0.3*ones(1,nt) 1]; %처음에는 반지름 1까지 -> 0.3까지 -> 1까지

%a circle
t2 = 0:0.01:2*pi; % 360도 원
r2 = ones(1, length(t2)); %반지름 1

%Polar
figure(1);
h1 = polar (th, r1, 'r-'); hold on; %doc polar %[output:2caa38da]
h2 = polar (th+2/3*pi, r1, 'r-'); % 120도 %[output:2caa38da]
h3 = polar (th-2/3*pi, r1, 'r-'); % -120도 %총 360도 %[output:2caa38da]
h0 = polar (t2, 0.25*r2, 'r-'); %가운데 원 %[output:2caa38da]

set([h0 h1 h2 h3], 'LineWidth', 3); %[output:2caa38da]
hold off; %[output:2caa38da]
%Plot

figure(2); %[output:6097a27d]
h1 = plot(r1.*cos(th), r1.*sin(th), 'r-');  %[output:6097a27d]
hold on; %[output:6097a27d]
h2 = plot(r1.*cos(th+2/3*pi), r1.*sin(th+2/3*pi), 'r-'); %[output:6097a27d]
h3 = plot(r1.*cos(th-2/3*pi), r1.*sin(th-2/3*pi), 'r-'); %[output:6097a27d]
h0 = plot(0.25*r2.*cos(t2), 0.25*r2.*sin(t2), 'r-'); %[output:6097a27d]
set([h0 h1 h2 h3], 'LineWidth', 3); %[output:6097a27d]
axis square; %[output:6097a27d]
hold off; %[output:6097a27d]
%Patch - filled polypons plot과 거의 동일 -색상 입힘

figure(3); %[output:04efa873]
h1 = patch(r1.*cos(th), r1.*sin(th), 'k');  %[output:04efa873]
hold on; %[output:04efa873]
h2 = patch(r1.*cos(th+2/3*pi), r1.*sin(th+2/3*pi), 'k'); %[output:04efa873]
h3 = patch(r1.*cos(th-2/3*pi), r1.*sin(th-2/3*pi), 'k'); %[output:04efa873]
h0 = patch(0.25*r2.*cos(t2), 0.25*r2.*sin(t2), 'k'); %[output:04efa873]
set(gca, 'Color', 'yellow') %바탕색 설정 doc gca %[output:04efa873]
axis square; %[output:04efa873]
hold off; %[output:04efa873]
%%
%[text] ## Coloring Patches
clear;
xdata = [2 2 0 2 5;
         2 8 2 4 5;
         8 8 2 4 8;]; %열이 5개 -> 총 5개의 도형 patch / 행 3개 -> 점 3개 연결 

ydata = [4 4 4 2 0;
         8 4 6 3 2;
         4 0 4 8 2;];

cdata = [9 0 4 5 9; %색상의 colormapeditor에서 결정됨 / 첫 번째 삼각형(9, 15, 8
         15 2 5 7 8;
         8 3 0 7 6;];
%그러면 점 사이 값은 어떻게 채우는가?

%colormapeditor
figure(4); %[output:2b7eeaef]
p = patch(xdata, ydata, cdata ... %[output:2b7eeaef]
    ,'Marker', 'o', 'MarkerFaceColor', 'r' ... %[output:2b7eeaef]
    ,'FaceColor', 'none'); %x데이타, y데이터, color데이터 %[output:2b7eeaef]
set(p, 'EdgeColor', 'interp'); %'EdgeColor'를 'interpolation'하라(자연스럽게 그라데이션) %[output:2b7eeaef]
